//vip.opstream11.com/20230211/42763_393819cf/index.m3u8"}]}],"time":"43 phút/tập","description":"<p>Clark Kent giờ đây gánh đầy các lớp học tại Đại học Central Kansas, nhưng đó không phải là tất cả những gì anh ấy gánh vác. Anh ta mang toàn bộ trọng lượng của mình - có lẽ là của thế giới - định mệnh. Trong phần năm, Clark cuối cùng cũng bắt đầu chấp nhận số phận của mình và có những bước nhảy vọt để trở thành Người đàn ông thép. Anh ấy cũng qua đường với giáo sư Milton Fine, người có mặt ở Smallville sẽ có tác động tàn phá đến tình bạn vốn đã xấu đi của anh ấy với Lex.</p>","tmdb":{"type":"tv","id":"4604","season":5,"vote_average":8.2,"vote_count":4281},"modified":"2023-02-11T12:32:42.000Z","_image_preserved":true},{"id":"63e24f3bc76b89d00efd063a","_id":"63e24f3bc76b89d00efd063a","title":"Vũ Điệu Sôi Động","origin_name":"You Got Served","slug":"vu-dieu-soi-dong","year":2004,"type":"single","genre":[{"id":"620a22bae0fc277084dfd585","name":"Âm Nhạc","slug":"am-nhac"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"You Got Served - 2004","link_embed":"https://vip.opstream14.com/share/de4b763471b905676a7a4c8023ce184e","link_m3u8":"https://vip.opstream14.com/20230207/30729_1e69acc1/index.m3u8"}]}],"time":"95 Phút","description":"<p>Rad's Warehouse, các đội hip-hop giỏi nhất ở Los Angeles cạnh tranh để giành tiền và sự tôn trọng. Nhưng khi một nhóm ở ngoại ô phá vỡ bữa tiệc, đánh cắp các vũ công của họ - và các bước di chuyển của họ - hai người bạn hiếu chiến phải tập hợp lại để đại diện cho đường phố. Với sự tham gia của các ngôi sao hip-hop Marques Houston, Omari Grandberry, Lil' Kim và diễn viên hài Steve Harvey.</p>","tmdb":{"type":"movie","id":"14114","season":null,"vote_average":6.4,"vote_count":449},"modified":"2023-02-07T20:16:43.000Z","_image_preserved":true},{"id":"63e24fa4c76b89d00efd141b","_id":"63e24fa4c76b89d00efd141b","title":"Space Chimps","origin_name":"Space Chimps","slug":"space-chimps","year":2008,"type":"hoathinh","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"Space Chimps - 2008","link_embed":"https://vip.opstream14.com/share/00becd45cce07f2cc996fc254f2fcfc0","link_m3u8":"https://vip.opstream14.com/20230207/30722_47935c26/index.m3u8"}]}],"time":"81 Phút","description":"<p>Ba con tinh tinh được gửi vào vũ trụ để khám phá khả năng tồn tại sự sống ngoài hành tinh khi một vụ tai nạn tàu con thoi không người lái hạ cánh xuống một hành tinh chưa được khám phá.</p>","tmdb":{"type":"movie","id":"11802","season":null,"vote_average":4.9,"vote_count":474},"modified":"2023-02-07T20:18:28.000Z","_image_preserved":true},{"id":"63e25007c76b89d00efd2240","_id":"63e25007c76b89d00efd2240","title":"Yểu Điệu Thục Nữ","origin_name":"My Fair Lady","slug":"yeu-dieu-thuc-nu","year":1964,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a22bae0fc277084dfd585","name":"Âm Nhạc","slug":"am-nhac"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"My Fair Lady - 1964","link_embed":"https://vip.opstream14.com/share/00f42382da08bb47df2585a2590be0a7","link_m3u8":"https://vip.opstream14.com/20230207/30717_bf2e1f74/index.m3u8"}]}],"time":"170 Phút","description":"<p>Tác phẩm điện ảnh My Fair Lady - Yểu Điệu Thục Nữ được quay dưới sự chỉ đạo của đạo diễn George Cukor. Bộ phim âm nhạc này được công chiếu ra mắt khán giả vào năm 1964. Nội dung của bộ phim kể về cô gái xinh đẹp nhưng hoàn cảnh gia đình lại nghèo khổ, Eliza Doolittle (do Audrey Hepburn thủ vai). Cô làm nghề bán hoa cở Cockney. Một ngày vô tình cô gặp được một giáo sư ngôn ngữ học là Henry Higgins (do Rex Harrison thủ vai). Lần đầu tiên gặp gỡ, nhìn dáng vẻ nhem nhuốc cùng giọng nói vô cùng khó nghe, Henry đã phải thốt lên rằng một cô gái như Eliza không có quyền được sống. Vì vậy mà ông quyết định sẽ dạy dỗ Eliza để biến cô trở thành một vị tiểu thư. Nhưng họ không thể ngờ được rằng sợi dây tình cảm giữa hai người ...</p>","tmdb":{"type":"movie","id":"11113","season":null,"vote_average":7.501,"vote_count":1378},"modified":"2023-02-07T20:20:07.000Z","_image_preserved":true},{"id":"63e2506bc76b89d00efd2fc3","_id":"63e2506bc76b89d00efd2fc3","title":"Ticker","origin_name":"Ticker","slug":"ticker","year":2001,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620f84d291fa4af90ab6b3f4","name":"Bí ẩn","slug":"bi-an"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Ticker - 2001","link_embed":"https://vip.opstream14.com/share/a1352ed0ab1484e12a4b466e7680e7f8","link_m3u8":"https://vip.opstream14.com/20230207/30724_df83d53b/index.m3u8"}]}],"time":"92 Phút","description":"<p>Ray Nettles, một thám tử của San Francisco, và đối tác của anh ta là Fuzzy phải đối đầu với một trong những băng nhóm khủng bố nguy hiểm nhất của thành phố. Khi một trong những kẻ khủng bố, nhà khoa học xinh đẹp Claire Manning bị bắt, Swan, thủ lĩnh của bọn khủng bố, tuyên bố hắn sẽ cho nổ bom khắp thành phố nếu cô không được thả. Vì có thể xảy ra đổ máu, Nettles kêu gọi sự giúp đỡ của chuyên gia chất nổ Frank Glass...</p>","tmdb":{"type":"movie","id":"31002","season":null,"vote_average":3.659,"vote_count":126},"modified":"2023-02-07T20:21:47.000Z","_image_preserved":true},{"id":"63e25108c76b89d00efd4371","_id":"63e25108c76b89d00efd4371","title":"Tình Tay Ba","origin_name":"Two Lovers","slug":"tinh-tay-ba","year":2008,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Two Lovers - 2008","link_embed":"https://vip.opstream14.com/share/ba368424b735e1761bc78ea814268bc3","link_m3u8":"https://vip.opstream14.com/20230207/30726_2fe0b79a/index.m3u8"}]}],"time":"110 Phút","description":"<p>Là một câu chuyện tình lãng mạn diễn ra tại Thành phố New York, kể về Leonard, một người đàn ông quyến rũ nhưng đượm buồn vừa mới chuyển về sống với bố mẹ sau một mối tình tan vỡ. Bố mẹ Leonard cố gắng mai mối anh với Sandra, một cô gái ngọt ngào và xinh xắn và là con gái của một gia đình thân thiết. Bữa ăn gia đình trịnh trọng đã được chuẩn bị để hai người gặp gỡ nhau và Leonard đã đồng ý bắt đầu mối quan hệ nghiêm túc theo sự sắp xếp của bố mẹ. Nhưng một đêm nọ, Leonard nhìn ra ngoài cửa sổ phòng ngủ và nhìn thấy một người phụ nữ đẹp mê hồn mà Leonard chưa từng thấy trước đây - Michelle vừa mới chuyển tới và đang sống trong căn hộ do một người đàn ông mà cô đang cặp kè trả tiền cho. Cuộc tình tay ba bắt đầu...</p>","tmdb":{"type":"movie","id":"10362","season":null,"vote_average":6.856,"vote_count":896},"modified":"2023-02-07T20:24:24.000Z","_image_preserved":true},{"id":"63e251cac76b89d00efd5929","_id":"63e251cac76b89d00efd5929","title":"Yamato","origin_name":"男たちの大和／YAMATO","slug":"yamato","year":2005,"type":"single","genre":[{"id":"620a2253e0fc277084dfd339","name":"Chiến Tranh","slug":"chien-tranh"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Otoko-tachi no Yamato - 2005","link_embed":"https://vip.opstream14.com/share/42a61b38226d9f4a3bdeef465b616eb7","link_m3u8":"https://vip.opstream14.com/20230207/30720_c7032d7f/index.m3u8"}]}],"time":"143 Phút","description":"<p>Do Junya Sato đạo diễn và dựa trên một cuốn sách của Jun Henmi, \"Yamato\" có cốt truyện lấy bối cảnh thời hiện đại và sử dụng những đoạn hồi tưởng để kể câu chuyện về thủy thủ đoàn của thiết giáp hạm Nhật Bản trong Thế chiến II Yamato. Bộ phim chưa bao giờ được phát hành ở Hoa Kỳ, nơi các nhà phê bình đã xem nó đã so sánh sử thi quân sự với \"Titanic\" và \"Saving Private Ryan\".</p>","tmdb":{"type":"movie","id":"19659","season":null,"vote_average":5.474,"vote_count":38},"modified":"2023-02-07T20:27:38.000Z","_image_preserved":true},{"id":"63e252eac76b89d00efd796d","_id":"63e252eac76b89d00efd796d","title":"Asterix và Nữ Hoàng Ai Cập","origin_name":"Asterix and Cleopatra","slug":"asterix-va-nu-hoang-ai-cap","year":1968,"type":"hoathinh","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"}],"country":[{"id":"620a2378e0fc277084dfd972","name":"Pháp","slug":"phap"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"Asterix and Cleopatra - 1968","link_embed":"https://vip.opstream14.com/share/d34ff18d819ea9dfeda0f638eae589f0","link_m3u8":"https://vip.opstream14.com/20230207/30707_ba303652/index.m3u8"}]}],"time":"72 Phút","description":"<p>Anh hùng hoạt hình nổi tiếng Asterix và người bạn trung thành của mình Obelix du hành đến Ai Cập cổ đại để giúp Cleopatra xây dựng một ngôi nhà mùa hè mới. Cleopatra và Julius Caesar đã đặt cược, với việc Caesar đặt cược rằng dự án không thể hoàn thành trong thời gian vài tuần. Với sự giúp đỡ của một lọ thuốc ma thuật, Asterix đến để giải cứu Nữ hoàng sông Nile là Caesar và một kiến ​​trúc sư tức giận âm mưu chống lại họ.</p>","tmdb":{"type":"movie","id":"9929","season":null,"vote_average":6.946,"vote_count":1004},"modified":"2023-02-07T20:32:26.000Z","_image_preserved":true},{"id":"63e2535cc76b89d00efd8484","_id":"63e2535cc76b89d00efd8484","title":"Asterix Phiêu Lưu Ở Britain","origin_name":"Asterix in Britain","slug":"asterix-in-britain","year":1986,"type":"hoathinh","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"}],"country":[{"id":"620a2378e0fc277084dfd972","name":"Pháp","slug":"phap"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"Asterix in Britain - 1986","link_embed":"https://vip.opstream14.com/share/a5819c80f61198eabf3d3ffceec595de","link_m3u8":"https://vip.opstream14.com/20230207/30712_57af68ee/index.m3u8"}]}],"time":"79 Phút","description":"<p>Một ngôi làng nhỏ cổ kính của Anh vẫn chống lại quân xâm lược La Mã. Asterix và Obelix được mời giúp đỡ. Họ phải đối mặt với sương mù, mưa, bia ấm và thịt lợn luộc với nước sốt bạc hà, nhưng họ sẽ sớm gặp phải tình trạng người La Mã của Thống đốc Encyclopaedius Britannicus đang suy tàn và thất thủ. Cho đến khi một cuộc đua hoang dã để giành lấy một thùng thuốc ma thuật đưa họ vào cuộc uống rượu.</p>","tmdb":{"type":"movie","id":"9318","season":null,"vote_average":6.78,"vote_count":706},"modified":"2023-02-07T21:58:52.000Z","_image_preserved":true},{"id":"63e253dcc76b89d00efd90ff","_id":"63e253dcc76b89d00efd90ff","title":"Asterix Và Cuộc Đại Chiến","origin_name":"Asterix and the Big Fight","slug":"asterix-and-the-big-fight","year":1989,"type":"hoathinh","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"}],"country":[{"id":"620a2378e0fc277084dfd972","name":"Pháp","slug":"phap"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_d